import{_ as c,C as o,o as n,c as s,j as e,a as d,E as a,ag as l}from"./chunks/framework.HG0H2VLS.js";const v=JSON.parse('{"title":"Avatar","description":"","frontmatter":{},"headers":[],"relativePath":"components/avatar.md","filePath":"components/avatar.md"}'),h={name:"components/avatar.md"},p={id:"avatar",tabindex:"-1"};function u(g,t,f,m,x,b){const i=o("Badge"),r=o("ComponentDemo");return n(),s("div",null,[t[3]||(t[3]=e("hr",null,null,-1)),t[4]||(t[4]=e("h2",{id:"title-avatar",tabindex:"-1"},[d("title: Avatar "),e("a",{class:"header-anchor",href:"#title-avatar","aria-label":'Permalink to "title: Avatar"'},"​")],-1)),e("h1",p,[t[0]||(t[0]=d("Avatar ",-1)),a(i,{type:"info",text:"Design System"}),t[1]||(t[1]=d()),t[2]||(t[2]=e("a",{class:"header-anchor",href:"#avatar","aria-label":'Permalink to "Avatar <Badge type="info" text="Design System" />"'},"​",-1))]),t[5]||(t[5]=e("blockquote",null,[e("p",null,[e("strong",null,"80 variants"),d(" (Figma-formalised 2026-05-07)")])],-1)),a(r,{src:"/demos/src/components/Avatar/Avatar.html"}),t[6]||(t[6]=l('<h2 id="variant-matrix-verified-2026-05-07-from-figma-get-metadata-per-variant-get-design-context" tabindex="-1">Variant matrix (verified 2026-05-07 from Figma <code>get_metadata</code> + per-variant <code>get_design_context</code>) <a class="header-anchor" href="#variant-matrix-verified-2026-05-07-from-figma-get-metadata-per-variant-get-design-context" aria-label="Permalink to &quot;Variant matrix (verified 2026-05-07 from Figma `get_metadata` + per-variant `get_design_context`)&quot;">​</a></h2><p>Six independent axes:</p><table tabindex="0"><thead><tr><th>Axis</th><th>Values</th><th>CSS</th></tr></thead><tbody><tr><td>Size</td><td>1 (24px) · 2 (32px) · 3 (48px) · 4 (64px) · 5 (80px)</td><td><code>--size-2..5</code> (default = Size 1)</td></tr><tr><td>Shape</td><td>Round · Rounded</td><td><code>--rounded</code> (default = Round, radius-full)</td></tr><tr><td>Type</td><td>Default · Bordered · Placeholder · Initials</td><td><code>--bordered</code> · <code>--placeholder</code> · <code>--initials</code></td></tr><tr><td>Show Notification</td><td>True · False</td><td>structural — add <code>&lt;span class=&quot;avatar__dot&quot;&gt;</code> for True</td></tr><tr><td>Notification Color</td><td>Green · Red · Orange</td><td><code>__dot--green/--red/--orange</code> (only valid when Show Notification=True)</td></tr><tr><td>Checked</td><td>True · False</td><td><code>--checked</code> (only valid with Type=Default + Show Notification=False)</td></tr></tbody></table><p>Combined cell totals (per Figma component set):</p><ul><li>5 sizes × 2 shapes × Type=Default × 3 notification colours × Show Notification=True = <strong>30</strong></li><li>5 sizes × 2 shapes × Type=Default × Show Notification=False × Checked=False = <strong>10</strong></li><li>5 sizes × 2 shapes × Type=Default × Show Notification=False × Checked=True = <strong>10</strong></li><li>5 sizes × 2 shapes × Type=Bordered × Show Notification=False × Checked=False = <strong>10</strong></li><li>5 sizes × 2 shapes × Type=Placeholder × Show Notification=False × Checked=False = <strong>10</strong></li><li>5 sizes × 2 shapes × Type=Initials × Show Notification=False × Checked=False = <strong>10</strong></li></ul><p>Total = <strong>80 symbols</strong>, matching the metadata enumeration.</p><hr><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS</th></tr></thead><tbody><tr><td>Size=1</td><td>(no modifier — base <code>.avatar</code>)</td></tr><tr><td>Size=2</td><td><code>.avatar--size-2</code></td></tr><tr><td>Size=3</td><td><code>.avatar--size-3</code></td></tr><tr><td>Size=4</td><td><code>.avatar--size-4</code></td></tr><tr><td>Size=5</td><td><code>.avatar--size-5</code></td></tr><tr><td>Shape=Round</td><td>(no modifier — base <code>radius-full</code>)</td></tr><tr><td>Shape=Rounded</td><td><code>.avatar--rounded</code> (radius-md squircle)</td></tr><tr><td>Type=Default</td><td>(no modifier)</td></tr><tr><td>Type=Bordered</td><td><code>.avatar--bordered</code></td></tr><tr><td>Type=Placeholder</td><td><code>.avatar--placeholder</code> (+ Lucide <code>&lt;i data-lucide=&quot;user&quot;&gt;</code> child)</td></tr><tr><td>Type=Initials</td><td><code>.avatar--initials</code> (+ uppercase text)</td></tr><tr><td>Checked=True</td><td><code>.avatar--checked</code> (+ Lucide <code>&lt;i data-lucide=&quot;check&quot;&gt;</code> child)</td></tr><tr><td>Show Notification=True</td><td>structural — add <code>&lt;span class=&quot;avatar__dot avatar__dot--{green|red|orange}&quot;&gt;</code></td></tr><tr><td>Notification Color</td><td><code>.avatar__dot--green</code> · <code>.avatar__dot--red</code> · <code>.avatar__dot--orange</code></td></tr></tbody></table><hr><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><h3 id="sizing" tabindex="-1">Sizing <a class="header-anchor" href="#sizing" aria-label="Permalink to &quot;Sizing&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Size</th><th>Diameter</th><th>Token</th></tr></thead><tbody><tr><td>1</td><td>24px</td><td><code>--ai-spacing-6</code></td></tr><tr><td>2</td><td>32px</td><td><code>--ai-spacing-7</code></td></tr><tr><td>3</td><td>48px</td><td><code>--ai-spacing-9</code></td></tr><tr><td>4</td><td>64px</td><td><code>--ai-spacing-11</code></td></tr><tr><td>5</td><td>80px</td><td><code>--ai-spacing-13</code></td></tr></tbody></table><h3 id="shape" tabindex="-1">Shape <a class="header-anchor" href="#shape" aria-label="Permalink to &quot;Shape&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Shape</th><th>Token</th></tr></thead><tbody><tr><td>Round</td><td><code>--ai-radius-full</code></td></tr><tr><td>Rounded</td><td><code>--ai-radius-md</code> (8px squircle)</td></tr></tbody></table><h3 id="type-bordered" tabindex="-1">Type=Bordered <a class="header-anchor" href="#type-bordered" aria-label="Permalink to &quot;Type=Bordered&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Value</th></tr></thead><tbody><tr><td>Outline</td><td><code>1px solid var(--ai-border-secondary)</code></td></tr><tr><td>Outline offset</td><td><code>3px</code> (Figma uses a 4px gap; outline rendered at offset 3 + 1px width visually = 4px from photo)</td></tr></tbody></table><h3 id="type-placeholder" tabindex="-1">Type=Placeholder <a class="header-anchor" href="#type-placeholder" aria-label="Permalink to &quot;Type=Placeholder&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Background</td><td><code>--ai-surface-secondary</code></td></tr><tr><td>Icon colour</td><td><code>--ai-icon-secondary</code></td></tr><tr><td>Icon</td><td>Lucide <code>user</code>, with <strong>explicit per-size dimensions</strong> (NOT proportional)</td></tr></tbody></table><p><strong>Placeholder icon sizes per avatar size</strong> (verified from Figma — do not assume scaling):</p><table tabindex="0"><thead><tr><th>Avatar</th><th>Icon size</th><th>Token</th></tr></thead><tbody><tr><td>Size 1 (24px)</td><td>16px</td><td><code>--ai-icon-size-sm</code></td></tr><tr><td>Size 2 (32px)</td><td>20px</td><td><code>--ai-icon-size-md</code></td></tr><tr><td>Size 3 (48px)</td><td>24px</td><td><code>--ai-icon-size-lg</code></td></tr><tr><td>Size 4 (64px)</td><td>32px</td><td><code>--ai-icon-size-xl</code></td></tr><tr><td>Size 5 (80px)</td><td><strong>40px</strong></td><td>⚠ no token — hardcoded <code>40px</code></td></tr></tbody></table><p>⚠ <strong>Token gap:</strong> Size 5 placeholder icon is 40px; there&#39;s no <code>--ai-icon-size-2xl</code> token. Flagged for designer to add.</p><h3 id="type-initials" tabindex="-1">Type=Initials <a class="header-anchor" href="#type-initials" aria-label="Permalink to &quot;Type=Initials&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Background</td><td><code>--ai-surface-info-soft</code></td></tr><tr><td>Text colour</td><td><code>--ai-text-info</code></td></tr><tr><td>Font family</td><td><code>--ai-font-title</code></td></tr><tr><td>Font weight</td><td><code>--ai-font-semibold</code></td></tr><tr><td>Font size (Size 1)</td><td><code>--ai-font-fixed-xxs</code> (12px)</td></tr><tr><td>Font size (Size 2)</td><td><code>--ai-font-fixed-xs</code> (14px)</td></tr><tr><td>Font size (Size 3)</td><td><code>--ai-font-fixed-md</code> (18px)</td></tr><tr><td>Font size (Size 4)</td><td><code>--ai-font-fixed-xl</code> (22px)</td></tr><tr><td>Font size (Size 5)</td><td><code>--ai-font-fixed-3xl</code> (28px)</td></tr></tbody></table><h3 id="checked" tabindex="-1">Checked <a class="header-anchor" href="#checked" aria-label="Permalink to &quot;Checked&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Background</td><td><code>--ai-surface-success</code></td></tr><tr><td>Tick icon colour</td><td><code>--ai-btn-primary-text</code> (white in light + dark)</td></tr><tr><td>Tick icon</td><td>Lucide <code>check</code>, with <strong>explicit per-size dimensions</strong> (NOT proportional)</td></tr></tbody></table><p><strong>Checked tick sizes per avatar size</strong> (verified from Figma):</p><table tabindex="0"><thead><tr><th>Avatar</th><th>Tick size</th><th>Token</th></tr></thead><tbody><tr><td>Size 1 (24px)</td><td>16px</td><td><code>--ai-icon-size-sm</code></td></tr><tr><td>Size 2 (32px)</td><td>16px</td><td><code>--ai-icon-size-sm</code></td></tr><tr><td>Size 3 (48px)</td><td>24px</td><td><code>--ai-icon-size-lg</code></td></tr><tr><td>Size 4 (64px)</td><td>24px</td><td><code>--ai-icon-size-lg</code></td></tr><tr><td>Size 5 (80px)</td><td>24px</td><td><code>--ai-icon-size-lg</code></td></tr></tbody></table><p>Note: Size 1+2 share the small tick; Sizes 3+4+5 share the large tick. There&#39;s no <code>md</code> (20px) or <code>xl</code> (32px) tick — Figma quantises to two values.</p><h3 id="notification-dot" tabindex="-1">Notification dot <a class="header-anchor" href="#notification-dot" aria-label="Permalink to &quot;Notification dot&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Diameter (Sizes 1, 2)</td><td><code>--ai-spacing-3</code> (8px)</td></tr><tr><td>Diameter (Sizes 3, 4)</td><td><code>--ai-spacing-5</code> (16px)</td></tr><tr><td>Diameter (Size 5)</td><td><code>--ai-spacing-6</code> (24px)</td></tr><tr><td>Border / ring</td><td><code>1px solid --ai-surface-primary</code> (1.5px on Sizes 3-4, 2px on Size 5)</td></tr><tr><td>Notification Color = Green</td><td><code>--ai-surface-success</code></td></tr><tr><td>Notification Color = Red</td><td><code>--ai-surface-error</code></td></tr><tr><td>Notification Color = Orange</td><td><code>--ai-surface-warning</code></td></tr></tbody></table><p><strong>Position depends on Shape:</strong></p><table tabindex="0"><thead><tr><th>Shape</th><th>Avatar size</th><th>Dot position (top / right)</th></tr></thead><tbody><tr><td>Round</td><td>all</td><td><code>top: 0; right: 0</code> (corner of bounding box)</td></tr><tr><td>Rounded</td><td>Size 1</td><td><code>top: -3px; right: -2px</code></td></tr><tr><td>Rounded</td><td>Size 2</td><td><code>top: -2px; right: -2px</code></td></tr><tr><td>Rounded</td><td>Sizes 3, 4, 5</td><td><code>top: -8px; right: -8px</code></td></tr></tbody></table><p>On Rounded (squircle) avatars the dot is pulled OUTSIDE the bounding box with negative offsets so it visually clears the rounded corner. Offsets verified per-size from Figma — do not interpolate or assume.</p><p>No new tokens introduced. No primitive Tailwind colours used.</p><hr><h2 id="photo-clipping" tabindex="-1">Photo clipping <a class="header-anchor" href="#photo-clipping" aria-label="Permalink to &quot;Photo clipping&quot;">​</a></h2><p>The photo is clipped via <code>clip-path</code> on the <code>.portrait</code> element, NOT via <code>overflow: hidden</code> on <code>.avatar</code>. This keeps the notification dot — a sibling of the photo, positioned at top-right of <code>.avatar</code> — visible even though it sits at the corner where it overlaps the photo&#39;s circle.</p><table tabindex="0"><thead><tr><th>Shape</th><th>Clip</th></tr></thead><tbody><tr><td>Round</td><td><code>clip-path: circle(50%)</code></td></tr><tr><td>Rounded</td><td><code>clip-path: inset(0 round var(--ai-radius-md))</code></td></tr></tbody></table><hr><h2 id="composition-dependencies" tabindex="-1">Composition / dependencies <a class="header-anchor" href="#composition-dependencies" aria-label="Permalink to &quot;Composition / dependencies&quot;">​</a></h2><ul><li><strong>Portraits</strong> (<code>src/components/Portraits/</code>) — every photo content uses <code>&lt;img class=&quot;portrait&quot;&gt;</code> and the Portraits CSS is imported. Composes naturally.</li><li>Lucide icons — required for Placeholder (<code>user</code>) and Checked (<code>check</code>).</li><li>No JS.</li></ul><hr><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><ul><li>Photo <code>&lt;img&gt;</code> carries an <code>alt</code> describing the person, OR <code>alt=&quot;&quot;</code> for purely decorative usage (e.g. inside a button that already names the user).</li><li>Type=Placeholder: wrap with <code>aria-label=&quot;No portrait&quot;</code> (or context-specific) since the silhouette is decorative.</li><li>Type=Initials: wrap with <code>aria-label=&quot;Mark Foster&quot;</code> (the full name) so SR users hear the name, not the letters.</li><li>Checked: typically used inside a row that already conveys &quot;selected&quot; via <code>aria-current</code> or similar — the avatar swap is purely visual.</li><li>Notification dot: <code>aria-hidden=&quot;true&quot;</code> (decorative). The actual notification context (e.g. &quot;3 new messages&quot;) should live in the surrounding markup or as <code>aria-label</code> on the parent container.</li></ul><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><ul><li>2026-05-07 (initial rebuild): Full rebuild after the designer formalised the new variant matrix in Figma. Pre-existing code-first additions (<code>--rounded</code>, <code>--bordered</code>, <code>--placeholder</code>, <code>--initials</code>, status-dot colour modifiers) were re-derived from the Figma source rather than carried over. Token bindings changed for several types: <ul><li><code>--bordered</code>: outline tightened to 1px <code>--ai-border-secondary</code> outside (was 2px <code>--ai-surface-contrast</code> inside)</li><li><code>--placeholder</code>: bg <code>--ai-surface-secondary</code>, icon <code>--ai-icon-secondary</code> (was <code>--ai-surface-contrast</code> / <code>--ai-text-invert</code>)</li><li><code>--initials</code>: bg <code>--ai-surface-info-soft</code>, text <code>--ai-text-info</code> (was <code>--ai-surface-brand-soft</code> / <code>--ai-surface-brand-dark</code>)</li><li>Notification dot colour modifiers renamed to match the Figma <code>Notification Color</code> enum: <code>--green</code> / <code>--red</code> / <code>--orange</code> (was <code>--online</code> / <code>--away</code> / <code>--busy</code> / <code>--offline</code>).</li></ul></li><li>2026-05-07 (correction): Initial rebuild assumed proportional 67% icon scaling and identical dot positioning across shapes. Both wrong. Re-fetched per-size variants and corrected: <ul><li><strong>Checked tick</strong> sizes are explicit per Figma: 16px for Sizes 1+2, 24px for Sizes 3+4+5 (not 67% of avatar).</li><li><strong>Placeholder user icon</strong> sizes are explicit per Figma: 16/20/24/32/40px for Sizes 1/2/3/4/5 (not 67% of avatar). Size 5&#39;s 40px has no <code>--ai-icon-size-2xl</code> token — flagged.</li><li><strong>Notification dot</strong> on Shape=Rounded uses negative offsets (<code>top: -3 right: -2</code> for Size 1, <code>top: -2 right: -2</code> for Size 2, <code>top: -8 right: -8</code> for Sizes 3-5) to clear the squircle&#39;s rounded corners. Round shape stays at <code>top: 0; right: 0</code>.</li></ul></li><li>Pre-2026-05-07: Avatar had Size 1-5 + Show Notification + Checked, no Shape/Type/Notification Color axes.</li></ul><h2 id="figma" tabindex="-1">Figma <a class="header-anchor" href="#figma" aria-label="Permalink to &quot;Figma&quot;">​</a></h2><p><a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=68-5042" target="_blank" rel="noreferrer">Open in Figma</a></p>',50))])}const S=c(h,[["render",u]]);export{v as __pageData,S as default};
